function firstNonRepeated(str) {
  const freq = new Map();
  for (const char of str) {
    freq.set(char, (freq.get(char) || 0) + 1);
  }
  for (const char of str) {
    if (freq.get(char) === 1) return char;
  }
  return null;
}

function firstNonRepeatedArray(str) {
  const counts = new Uint8Array(128);
  for (const char of str) counts[char.charCodeAt(0)]++;
  for (const char of str) {
    if (counts[char.charCodeAt(0)] === 1) return char;
  }
  return null;
}

function firstNonRepeatedSet(str) {
  const chars = [...new Set(str)];
  return chars.find(char => str.indexOf(char) === str.lastIndexOf(char)) || null;
}
